"use strict";const t=require("../utils/request.js");exports.completeExercise=function(e,r={}){return t.post(`/task/exercise/${e}/complete`,null,{params:r})},exports.getTaskFlow=function(e){return t.get("/task/flow",{date:e})},exports.getTodayTask=function(){return t.get("/task/today")},exports.startTask=function(e){return t.post(`/task/${e}/start`)},exports.startTodayTask=function(){return t.post("/task/start")},exports.updateTaskOrder=function(e){return t.post("/task/flow/reorder",e)};
